```class Solution {
public:
    int maxSatisfied(vector<int>& customers, vector<int>& grumpy, int minutes) {
        int satisfiedCustomers = 0;
        int grumpyMinutes = 0;
        for (int i = 0; i < minutes; i++) {
            if (grumpy[i] == 0) {
                satisfiedCustomers += customers[i];
            } else {
                grumpyMinutes++;
            }
        }
        return satisfiedCustomers;
    }
};```

